<template>
  <view class="audio-page">
    <scroll-view 
      class="scroll-content" 
      scroll-y="true" 
      :enhanced="true" 
      :show-scrollbar="false"
      @scrolltolower="onReachBottom"
      :lower-threshold="100"
      :refresher-enabled="true"
      :refresher-triggered="isRefreshingPull"
      @refresherrefresh="onPullRefresh"
      refresher-background="#f7fbf7"
    >
      <!-- 加载状态 -->
      <view v-if="isLoading && feed.list.length === 0" class="loading-container">
        <view class="pulse"></view>
        <text class="loading-text">屁趣音效装填中...</text>
      </view>

      <!-- 错误状态 -->
      <view v-else-if="errorMessage" class="error-container">
        <text class="error-emoji">😅</text>
        <text class="error-text">{{ errorMessage }}</text>
        <button class="retry-btn" @click="refreshFeed">再试一次</button>
      </view>

      <!-- 空状态 -->
      <view v-else-if="feed.empty" class="empty-container">
        <text class="empty-emoji">🫧</text>
        <text class="empty-title">音频库还在建造</text>
        <text class="empty-desc">管理员正在上传屁趣音效，稍后再来逛逛吧～</text>
      </view>

      <!-- 内容区域 -->
      <block v-else>
        <!-- 音频卡片列表 -->
        <view class="audio-list">
          <view
            class="audio-card"
            v-for="item in feed.list"
            :key="item.id"
            :style="getCardStyle(item)"
            @click="togglePlay(item)"
          >
            <!-- 左侧图片 -->
            <view class="card-image-wrapper">
              <image
                v-if="item.image"
                :src="item.image"
                class="card-image"
                mode="aspectFill"
              />
              <view v-else class="card-image placeholder">
                <text class="placeholder-emoji">💨</text>
              </view>
              <!-- 播放状态指示器 - 竖线滑过效果 -->
              <view v-if="playingId === item.id" class="play-indicator">
                <view class="scan-line scan-line-1"></view>
                <view class="scan-line scan-line-2"></view>
                <view class="scan-line scan-line-3"></view>
              </view>
            </view>

            <!-- 右侧信息 -->
            <view class="card-content">
              <view class="card-header">
                <text class="card-title">{{ item.name }}</text>
                <text class="card-desc">{{ item.description || item.moodText }}</text>
              </view>

              <!-- 标签和操作区域（水平对齐，居右） -->
              <view class="card-tags-action-row">
                <!-- 标签区域 -->
                <view class="card-tags" v-if="item.tags && item.tags.length">
                  <view class="card-tag" v-for="tag in item.tags.slice(0, 3)" :key="tag">
                    {{ tag }}
                  </view>
                  <text v-if="item.tags.length > 3" class="more-tags">+{{ item.tags.length - 3 }}</text>
                </view>

                <!-- 播放按钮 -->
                <view class="card-action">
                  <view class="play-btn" :class="{ playing: playingId === item.id }">
                    <image 
                      class="play-icon" 
                      :src="playingId === item.id ? '/static/img/24gf-pause2.png' : '/static/img/24gf-play.png'"
                      mode="aspectFit"
                    />
                    <text class="play-text">{{ playingId === item.id ? '暂停' : '播放' }}</text>
                  </view>
                </view>
              </view>
            </view>
          </view>
        </view>

        <!-- 上拉刷新提示 -->
        <view v-if="isRefreshing" class="refresh-tip">
          <view class="refresh-spinner"></view>
          <text class="refresh-text">正在刷新...</text>
        </view>

        <!-- 底部间距 -->
        <view class="footer-spacer"></view>
      </block>
    </scroll-view>
  </view>
</template>

<script setup>
import { ref, onMounted, onUnmounted } from 'vue'
import { getAudioLibraryFeedAPI } from '@/src/api/audio.js'

const feed = ref({
  list: [],
  empty: false,
  total: 0
})

const isLoading = ref(true)
const isRefreshing = ref(false) // 上拉刷新状态
const isRefreshingPull = ref(false) // 下拉刷新状态
const errorMessage = ref('')
const playingId = ref(null)
let innerAudioContext = null

// 分页相关
const currentPage = ref(1)
const pageSize = ref(20)
const hasMore = ref(true) // 是否还有更多数据

// 获取卡片样式
const getCardStyle = (item) => {
  const color = item.accentColor || '#FFD3B6'
  return {
    background: `linear-gradient(135deg, ${color}15 0%, ${color}08 50%, #ffffff 100%)`,
    borderColor: `${color}40`
  }
}

// 音频播放相关
const ensureAudioContext = () => {
  if (!innerAudioContext) {
    try {
      innerAudioContext = uni.createInnerAudioContext()
      if (!innerAudioContext) {
        throw new Error('无法创建音频上下文')
      }
      innerAudioContext.autoplay = false
      innerAudioContext.obeyMuteSwitch = false
      
      innerAudioContext.onEnded(() => {
        playingId.value = null
      })
      
      innerAudioContext.onStop(() => {
        playingId.value = null
      })
      
      innerAudioContext.onError((err) => {
        console.error('音频播放错误:', err)
        playingId.value = null
        
        // 根据错误类型显示不同的提示
        let errorMsg = '音频播放失败'
        if (err && typeof err === 'object') {
          if (err.errMsg) {
            const errMsgLower = err.errMsg.toLowerCase()
            // 解码错误
            if (errMsgLower.includes('decode') || 
                errMsgLower.includes('解码') || 
                errMsgLower.includes('unable to decode audio data') ||
                errMsgLower.includes('set audio src') && errMsgLower.includes('fail')) {
              // 检查文件格式
              const currentUrl = innerAudioContext?.src || ''
              if (currentUrl.includes('.wav') || currentUrl.includes('.WAV')) {
                errorMsg = '该手机不支持此音频播放'
              } else {
                errorMsg = '音频格式不支持或文件损坏，请检查文件格式'
              }
            } else if (errMsgLower.includes('network') || errMsgLower.includes('网络')) {
              errorMsg = '网络错误，请检查网络连接'
            } else if (errMsgLower.includes('404') || errMsgLower.includes('not found')) {
              errorMsg = '音频文件不存在'
            } else if (errMsgLower.includes('timeout')) {
              errorMsg = '音频加载超时，请稍后重试'
            }
          }
        }
        
        uni.showToast({
          title: errorMsg,
          icon: 'none',
          duration: 2500
        })
        
        // 清理音频上下文，下次重新创建
        try {
          if (innerAudioContext) {
            innerAudioContext.destroy()
          }
        } catch (e) {
          console.error('清理音频上下文失败:', e)
        }
        innerAudioContext = null
      })
      
      innerAudioContext.onCanplay(() => {
        // 音频可以播放时的回调
        console.log('音频加载完成，可以播放')
      })
      
      innerAudioContext.onWaiting(() => {
        // 音频加载中的回调
        console.log('音频加载中...')
      })
    } catch (error) {
      console.error('创建音频上下文失败:', error)
      uni.showToast({
        title: '音频初始化失败',
        icon: 'none',
        duration: 2000
      })
      innerAudioContext = null
    }
  }
}

const destroyAudio = () => {
  if (innerAudioContext) {
    try {
      innerAudioContext.stop()
      innerAudioContext.destroy()
    } catch (e) {
      console.error('销毁音频上下文失败:', e)
    }
    innerAudioContext = null
  }
}

// 验证 URL 是否有效
const isValidUrl = (url) => {
  if (!url || typeof url !== 'string') {
    return false
  }
  // 检查是否是有效的 URL 格式
  try {
    new URL(url)
    return true
  } catch {
    // 如果不是完整 URL，检查是否是相对路径
    return url.startsWith('/') || url.startsWith('http://') || url.startsWith('https://')
  }
}

const togglePlay = (card) => {
  if (!card?.url) {
    uni.showToast({
      title: '音频地址缺失',
      icon: 'none',
      duration: 2000
    })
    return
  }
  
  // 验证 URL
  if (!isValidUrl(card.url)) {
    uni.showToast({
      title: '音频地址格式错误',
      icon: 'none',
      duration: 2000
    })
    return
  }
  
  // 如果正在播放同一个音频，则停止
  if (playingId.value === card.id) {
    try {
      if (innerAudioContext) {
        innerAudioContext.stop()
      }
      playingId.value = null
    } catch (error) {
      console.error('停止音频失败:', error)
      playingId.value = null
    }
    return
  }
  
  // 停止当前播放的音频
  if (innerAudioContext && playingId.value !== null) {
    try {
      innerAudioContext.stop()
    } catch (error) {
      console.error('停止当前音频失败:', error)
    }
  }
  
  // 创建或确保音频上下文存在
  ensureAudioContext()
  
  if (!innerAudioContext) {
    uni.showToast({
      title: '音频播放器初始化失败',
      icon: 'none',
      duration: 2000
    })
    return
  }
  
  try {
    // 检查文件格式，给出提示
    const urlLower = card.url.toLowerCase()
    const unsupportedFormats = ['.wav', '.flac', '.ogg', '.aiff']
    const hasUnsupportedFormat = unsupportedFormats.some(format => urlLower.includes(format))
    
    if (hasUnsupportedFormat) {
      console.warn('检测到可能不支持的音频格式:', card.url)
      // 仍然尝试播放，但会在错误回调中给出更明确的提示
    }
    
    // 设置音频源
    // 注意：在微信小程序中，如果文件格式不支持，onError 会在稍后异步触发
    innerAudioContext.src = card.url
    
    // 设置播放状态（如果后续出错，onError 会清理这个状态）
    playingId.value = card.id
    
    // 延迟播放，给音频一些加载时间
    // 如果文件格式不支持，onError 会在这之前触发并清理状态
    setTimeout(() => {
      try {
        // 检查状态是否仍然有效（没有被错误回调清理）
        if (innerAudioContext && 
            playingId.value === card.id && 
            innerAudioContext.src === card.url) {
          innerAudioContext.play()
        }
      } catch (playError) {
        console.error('播放音频失败:', playError)
        playingId.value = null
        uni.showToast({
          title: '播放失败，请稍后重试',
          icon: 'none',
          duration: 2000
        })
        
        // 清理音频上下文
        try {
          if (innerAudioContext) {
            innerAudioContext.destroy()
          }
        } catch (e) {
          console.error('清理音频上下文失败:', e)
        }
        innerAudioContext = null
      }
    }, 100)
  } catch (error) {
    console.error('设置音频源失败:', error)
    playingId.value = null
    
    // 检查是否是解码错误
    const errorMsg = error?.message || error?.toString() || ''
    if (errorMsg.includes('decode') || errorMsg.includes('解码')) {
      uni.showToast({
        title: '该手机音频格式不支持，请使用其他手机播放',
        icon: 'none',
        duration: 2500
      })
    } else {
      uni.showToast({
        title: '播放失败，请稍后重试',
        icon: 'none',
        duration: 2000
      })
    }
    
    // 如果设置失败，清理音频上下文
    try {
      if (innerAudioContext) {
        innerAudioContext.destroy()
      }
    } catch (e) {
      console.error('清理音频上下文失败:', e)
    }
    innerAudioContext = null
  }
}

const normalizeFeed = (data) => {
  if (!data) {
    return {
      list: [],
      empty: true,
      total: 0
    }
  }
  return {
    list: data.list || [],
    empty: data.empty || false,
    total: data.total || 0
  }
}

const loadFeed = async (isRefresh = false, isPullRefresh = false) => {
  if (isPullRefresh) {
    isRefreshingPull.value = true
  } else if (isRefresh) {
    isRefreshing.value = true
  } else {
    isLoading.value = true
  }
  errorMessage.value = ''
  
  try {
    // 如果是下拉刷新，重置页码和列表
    if (isPullRefresh) {
      currentPage.value = 1
      feed.value.list = []
      hasMore.value = true
    }
    
    const { data } = await getAudioLibraryFeedAPI({
      page: currentPage.value,
      pageSize: pageSize.value
    })
    
    if (data.code === 0) {
      const newFeed = normalizeFeed(data.data)
      
      if (currentPage.value === 1) {
        // 第一页，替换数据
        feed.value = newFeed
      } else {
        // 加载更多，追加数据
        feed.value.list = [...feed.value.list, ...newFeed.list]
        feed.value.total = newFeed.total
        feed.value.empty = feed.value.list.length === 0
      }
      
      // 判断是否还有更多数据
      hasMore.value = feed.value.list.length < feed.value.total
      
      // 如果还有更多数据，页码加1，准备下次加载
      if (hasMore.value) {
        currentPage.value++
      }
    } else {
      errorMessage.value = data.msg || '加载失败，请稍后重试'
    }
  } catch (error) {
    errorMessage.value = '网络走神了，稍后再试'
  } finally {
    isLoading.value = false
    isRefreshing.value = false
    isRefreshingPull.value = false
  }
}

const refreshFeed = () => {
  currentPage.value = 1
  feed.value.list = []
  hasMore.value = true
  loadFeed(true, false)
}

// 下拉刷新
const onPullRefresh = () => {
  if (isRefreshingPull.value || isLoading.value || isRefreshing.value) {
    return
  }
  loadFeed(false, true)
}

// 上拉加载更多
const onReachBottom = () => {
  if (isRefreshing.value || isLoading.value || isRefreshingPull.value || !hasMore.value) {
    return
  }
  // 加载下一页
  loadFeed(true, false)
}

onMounted(() => {
  loadFeed()
})

onUnmounted(() => {
  destroyAudio()
})
</script>

